import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"中国科学技术馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/science-center.md","filePath":"museums/science-center.md","lastUpdated":null}'),n={name:"museums/science-center.md"};function o(i,t,d,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="中国科学技术馆" tabindex="-1">中国科学技术馆 <a class="header-anchor" href="#中国科学技术馆" aria-label="Permalink to &quot;中国科学技术馆&quot;">​</a></h1><blockquote><p>&quot;中国唯一的国家级综合性科技馆，探索科学的奇妙世界。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中国科学技术馆（简称科技馆）是国家级综合性科技馆，是中国唯一的国家级科技馆，也是世界上规模最大的科技馆之一。科技馆通过丰富的互动展品，向公众普及科学知识，展示科技发展历程，激发科学兴趣。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:30-17:00（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">主展厅30元，儿童科学乐园20-30元，球幕影院30元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">科技馆官网或微信公众号预约</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁8号线奥林匹克公园站B口</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区北辰东路5号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="筹建" tabindex="-1">筹建 <a class="header-anchor" href="#筹建" aria-label="Permalink to &quot;筹建&quot;">​</a></h3><p>中国科技馆的建设始于1958年，但因历史原因多次中断。1984年，在邓小平等党和国家领导人的关怀下，工程重新启动。</p><h3 id="老馆时期" tabindex="-1">老馆时期 <a class="header-anchor" href="#老馆时期" aria-label="Permalink to &quot;老馆时期&quot;">​</a></h3><p>1988年，中国科技馆一期工程竣工开放，位于安华桥畔。老馆开放后接待了大量观众，但由于场地限制，展品更新较慢。</p><h3 id="新馆建设" tabindex="-1">新馆建设 <a class="header-anchor" href="#新馆建设" aria-label="Permalink to &quot;新馆建设&quot;">​</a></h3><p>2006年，科技馆新馆奠基。新馆位于奥林匹克公园内，建筑面积10.2万平方米，于2009年正式开放。新馆规模宏大，设施先进，成为世界上规模最大的科技馆之一。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观设计" tabindex="-1">外观设计 <a class="header-anchor" href="#外观设计" aria-label="Permalink to &quot;外观设计&quot;">​</a></h3><p>科技馆新馆由若干巨型积木般的长方体相互咬合而成，寓意&quot;解锁&quot;和&quot;探秘&quot;。建筑外观现代感强，与奥林匹克公园整体风格协调。</p><h3 id="内部结构" tabindex="-1">内部结构 <a class="header-anchor" href="#内部结构" aria-label="Permalink to &quot;内部结构&quot;">​</a></h3><p>科技馆分为四层，设有五大主题展厅：</p><table tabindex="0"><thead><tr><th style="text-align:left;">楼层</th><th style="text-align:left;">展厅</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">一层</td><td style="text-align:left;">华夏之光</td><td style="text-align:left;">中国古代科技成就</td></tr><tr><td style="text-align:left;">二层</td><td style="text-align:left;">探索与发现</td><td style="text-align:left;">基础科学</td></tr><tr><td style="text-align:left;">三层</td><td style="text-align:left;">科技与生活</td><td style="text-align:left;">现代科技应用</td></tr><tr><td style="text-align:left;">四层</td><td style="text-align:left;">挑战与未来</td><td style="text-align:left;">前沿科技</td></tr><tr><td style="text-align:left;">地下</td><td style="text-align:left;">特效影院</td><td style="text-align:left;">球幕、巨幕、4D等</td></tr></tbody></table><h2 id="展厅介绍" tabindex="-1">展厅介绍 <a class="header-anchor" href="#展厅介绍" aria-label="Permalink to &quot;展厅介绍&quot;">​</a></h2><h3 id="华夏之光" tabindex="-1">华夏之光 <a class="header-anchor" href="#华夏之光" aria-label="Permalink to &quot;华夏之光&quot;">​</a></h3><p>「华夏之光」展厅展示中国古代科技成就，是科技馆最具特色的展厅之一。</p><h4 id="重点展品" tabindex="-1">重点展品 <a class="header-anchor" href="#重点展品" aria-label="Permalink to &quot;重点展品&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">展品</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">水转翻车</td><td style="text-align:left;">古代灌溉机械</td></tr><tr><td style="text-align:left;">候风地动仪</td><td style="text-align:left;">张衡发明的地震仪（复原）</td></tr><tr><td style="text-align:left;">应县木塔</td><td style="text-align:left;">中国古建筑模型</td></tr><tr><td style="text-align:left;">古代天文仪器</td><td style="text-align:left;">浑天仪、简仪等</td></tr><tr><td style="text-align:left;">四大发明</td><td style="text-align:left;">造纸、印刷、火药、指南针</td></tr><tr><td style="text-align:left;">中医中药</td><td style="text-align:left;">针灸、脉诊等传统医学</td></tr></tbody></table><h3 id="探索与发现" tabindex="-1">探索与发现 <a class="header-anchor" href="#探索与发现" aria-label="Permalink to &quot;探索与发现&quot;">​</a></h3><p>「探索与发现」展厅以基础科学为主题，设有&quot;物质之妙&quot;&quot;光影之绚&quot;&quot;电磁之奥&quot;&quot;运动之律&quot;&quot;宇宙之奇&quot;&quot;数学之魅&quot;等展区。</p><h4 id="互动体验" tabindex="-1">互动体验 <a class="header-anchor" href="#互动体验" aria-label="Permalink to &quot;互动体验&quot;">​</a></h4><ul><li><strong>光影之绚</strong>：通过光学展品探索光的奥秘</li><li><strong>电磁之奥</strong>：体验静电、电磁感应等现象</li><li><strong>运动之律</strong>：探索力与运动的关系</li><li><strong>宇宙之奇</strong>：了解天体运行的规律</li></ul><h3 id="科技与生活" tabindex="-1">科技与生活 <a class="header-anchor" href="#科技与生活" aria-label="Permalink to &quot;科技与生活&quot;">​</a></h3><p>「科技与生活」展厅展示现代科技在日常生活中的应用，设有&quot;衣食之本&quot;&quot;健康之路&quot;&quot;居家之道&quot;&quot;信息之桥&quot;&quot;机械之巧&quot;等展区。</p><h4 id="重点内容" tabindex="-1">重点内容 <a class="header-anchor" href="#重点内容" aria-label="Permalink to &quot;重点内容&quot;">​</a></h4><ul><li>现代农业技术</li><li>医学与健康</li><li>智能家居</li><li>信息技术</li><li>人工智能</li></ul><h3 id="挑战与未来" tabindex="-1">挑战与未来 <a class="header-anchor" href="#挑战与未来" aria-label="Permalink to &quot;挑战与未来&quot;">​</a></h3><p>「挑战与未来」展厅展示人类面临的挑战和未来的发展方向，设有&quot;地球述说&quot;&quot;能源世界&quot;&quot;新型材料&quot;&quot;基因生命&quot;&quot;海洋开发&quot;&quot;太空探索&quot;等展区。</p><h4 id="重点内容-1" tabindex="-1">重点内容 <a class="header-anchor" href="#重点内容-1" aria-label="Permalink to &quot;重点内容&quot;">​</a></h4><ul><li>气候变化与环境保护</li><li>新能源技术</li><li>基因工程</li><li>深海探测</li><li>航空航天</li></ul><h2 id="特效影院" tabindex="-1">特效影院 <a class="header-anchor" href="#特效影院" aria-label="Permalink to &quot;特效影院&quot;">​</a></h2><p>科技馆设有四大特效影院，提供震撼的观影体验：</p><table tabindex="0"><thead><tr><th style="text-align:left;">影院</th><th style="text-align:left;">特色</th><th style="text-align:center;">票价</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>球幕影院</strong></td><td style="text-align:left;">半球形银幕，沉浸感强</td><td style="text-align:center;">30元</td></tr><tr><td style="text-align:left;"><strong>巨幕影院</strong></td><td style="text-align:left;">超大银幕，清晰度高</td><td style="text-align:center;">30元</td></tr><tr><td style="text-align:left;"><strong>4D影院</strong></td><td style="text-align:left;">座椅震动、喷水、刮风</td><td style="text-align:center;">30元</td></tr><tr><td style="text-align:left;"><strong>动感影院</strong></td><td style="text-align:left;">座椅随影片移动</td><td style="text-align:center;">30元</td></tr></tbody></table><h2 id="儿童科学乐园" tabindex="-1">儿童科学乐园 <a class="header-anchor" href="#儿童科学乐园" aria-label="Permalink to &quot;儿童科学乐园&quot;">​</a></h2><p>专为3-8岁儿童设计的科学乐园，设有&quot;小小建筑师&quot;&quot;开心农场&quot;&quot;科学城堡&quot;等主题区域，让小朋友在游戏中学习科学知识。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在官网或微信预约门票</li><li><strong>实名制</strong>：入场需携带身份证</li><li><strong>影院预约</strong>：特效影院需单独预约</li><li><strong>儿童限制</strong>：部分展品有身高年龄限制</li></ol><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>亲子路线（约4-5小时）</strong>：</p><p>儿童科学乐园 → 华夏之光（互动体验） → 探索与发现（光影、电磁） → 午餐 → 4D影院 → 科技与生活</p><p><strong>成人路线（约5-6小时）</strong>：</p><p>华夏之光 → 探索与发现（完整体验） → 科技与生活 → 午餐 → 挑战与未来 → 球幕影院</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>穿着舒适</strong>：需要大量互动，穿舒适的衣服和鞋子</li><li><strong>预留时间</strong>：展厅内容丰富，建议预留充足时间</li><li><strong>餐饮选择</strong>：地下有餐厅，也可自带食物</li><li><strong>避开高峰</strong>：周末和节假日人很多，建议工作日前往</li><li><strong>讲解服务</strong>：可租借语音导览或参加定时讲解</li><li><strong>拍照记录</strong>：鼓励拍照记录有趣的科学现象</li></ol><h3 id="周边游览" tabindex="-1">周边游览 <a class="header-anchor" href="#周边游览" aria-label="Permalink to &quot;周边游览&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">奥林匹克森林公园</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">城市绿肺</td></tr><tr><td style="text-align:left;">鸟巢（国家体育场）</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">2008年奥运主会场</td></tr><tr><td style="text-align:left;">水立方（国家游泳中心）</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">奥运游泳场馆</td></tr><tr><td style="text-align:left;">奥林匹克塔</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">俯瞰奥运公园</td></tr><tr><td style="text-align:left;">中国工艺美术馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">传统工艺美术</td></tr></tbody></table><h2 id="教育意义" tabindex="-1">教育意义 <a class="header-anchor" href="#教育意义" aria-label="Permalink to &quot;教育意义&quot;">​</a></h2><p>中国科技馆是国家级科普教育基地，承担着提高全民科学素质的重要使命。正如爱因斯坦所说：</p><blockquote><p>&quot;好奇心比知识更重要。&quot;</p></blockquote><p>科技馆通过互动体验，激发观众的好奇心和探索欲，是亲子游和学生科普教育的绝佳选择。</p><hr><p><strong>📍 地址</strong>：北京市朝阳区北辰东路5号 <strong>📞 电话</strong>：010-59041000 <strong>🌐 官网</strong>：<a href="http://www.cstm.org.cn" target="_blank" rel="noreferrer">www.cstm.org.cn</a><strong>📱 预约</strong>：关注「中国科学技术馆」微信公众号预约</p>',59)])])}const q=e(n,[["render",o]]);export{x as __pageData,q as default};
